[id:"spec-ttt-1", %%:1]
INF(@spec>@reader): #TicTacToeSpec{
  types: [
    #Player{value: "X" | "O"},
    #Cell{value: #Player | _},
    #Board{
      cells: [[#Cell, #Cell, #Cell], [#Cell, #Cell, #Cell], [#Cell, #Cell, #Cell]],
      turn: #Player,
      size: 3
    },
    #Move{player: #Player, row: 0..2, col: 0..2},
    #GameState{board: #Board, status: #Status},
    #Status{value: #ongoing | #won{winner: #Player} | #draw}
  ],
  rules: {
    valid_move:       forall($m: #Move, cell_at($m.row, $m.col) = _),
    correct_turn:     forall($m: #Move, $m.player = $board.turn),
    in_bounds:        forall($m: #Move, $m.row >= 0 & $m.row <= 2 & $m.col >= 0 & $m.col <= 2),
    win_row:          exists($r: 0..2, cell($r,0) = cell($r,1) & cell($r,1) = cell($r,2) & cell($r,0) != _),
    win_col:          exists($c: 0..2, cell(0,$c) = cell(1,$c) & cell(1,$c) = cell(2,$c) & cell(0,$c) != _),
    win_diag_main:    cell(0,0) = cell(1,1) & cell(1,1) = cell(2,2) & cell(0,0) != _,
    win_diag_anti:    cell(0,2) = cell(1,1) & cell(1,1) = cell(2,0) & cell(0,2) != _,
    draw:             !exists($r: 0..2, exists($c: 0..2, cell($r,$c) = _)) & !winner($board),
    next_turn:        $board.turn = "X" -> "O" | "O" -> "X"
  },
  functions: {
    cell_at:    cell_at($r, $c) -> $board.cells[$r][$c],
    winner:     winner($board) -> win_row($board) | win_col($board) | win_diag_main($board) | win_diag_anti($board),
    apply_move: apply_move($board, $m) ->
                  if(!valid_move($m) | !correct_turn($m) | !in_bounds($m),
                    #error{msg:"invalid move"},
                    set(cell_at($m.row, $m.col), $m.player) -> set($board.turn, next_turn($board.turn))
                  ),
    game_over:  game_over($board) ->
                  if(winner($board),
                    #won{winner: winning_player($board)},
                    if(draw($board),
                      #draw,
                      #ongoing
                    )
                  ),
    winning_player: winning_player($board) ->
                  if(win_row($board) | win_col($board) | win_diag_main($board) | win_diag_anti($board),
                    winning_value($board),
                    _
                  )
  },
  invariants: {
    turn_alternates:  forall($m1: #Move, $m2: #Move, $m1.player != $m2.player),
    board_immutable:  forall($c: #Cell, $c.value != _ -> $c.value = const),
