  ∀t∈Task: t.priority∈{1,2,3,4,5}
  ∀t∈Task: t.deadline.at∈Timestamp

  ∀w∈Worker:
    w.status=busy ⇒ (w.current_task≠⊥)
  ∀w∈Worker:
    w.status=idle ⇒ (w.current_task=⊥)
  ∀w∈Worker:
