  ∀a₁,a₂∈Schedule.assignments:
    a₁≠a₂ ⇒ a₁.worker_id≠a₂.worker_id

  ∀a∈Schedule.assignments:
    ∃w∈Schedule.workers: w.id=a.worker_id ∧ w.status≠offline

  ∀t₁,t₂∈Schedule.tasks:
    (t₁.status=unassigned ∧ t₂.status=assigned
      ∧ t₁.priority > t₂.priority)
    ⇒ ¬∃w∈Schedule.workers: w.status=idle

