  unassigned≜λ(s:Schedule).
    {t∈s.tasks | t.status=unassigned}

  available_workers≜λ(s:Schedule).
    {w∈s.workers | w.status=idle}

  next_task≜λ(s:Schedule).
    let U≜unassigned(s)
    in  if U=∅ then ⊥
        else argmax_{t∈U}(
