    pre: t.status=unassigned
       ∧ w.status=idle
       ∧ w∈available_workers(s)
    post: s′≜s{
      tasks    ← s.tasks\{t} ∪ {t{status←assigned, assigned_to←w.id}},
      workers  ← s.workers\{w} ∪ {w{status←busy, current_task←t.id}},
      assignments ← s.assignments ∪ {Assignment{
